<?php namespace App\Services\RBAC; use App\Models\User; class PermissionService { public function getUserPermissions(User $user): array { return $user->getAllPermissions(); } public function hasPermission(User $user, string $perm): bool { $perms = $this->getUserPermissions($user); return in_array($perm, $perms) || $this->matchesWildcard($perm, $perms); } private function matchesWildcard($required, $available): bool { foreach ($available as $perm) { if (str_ends_with($perm, '.*')) { $prefix = substr($perm, 0, -2); if (strpos($required, $prefix) === 0) return true; } } return false; } }
